css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0f0f1a; color: #e2e8f0; transition: all 0.3s; }
body.light { background: #f8fafc; color: #1e293b; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 68px; border-bottom: 1px solid rgba(255,255,255,0.07); position: sticky; top: 0; background: rgba(15,15,26,0.9); backdrop-filter: blur(20px); z-index: 100; }
body.light nav { background: rgba(248,250,252,0.9); border-color: rgba(0,0,0,0.07); }
.logo { font-size: 22px; font-weight: 900; color: #a855f7; }
.links { display: flex; gap: 24px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; font-size: 15px; } .links a:hover { color: #a855f7; }
.theme-btn { cursor: pointer; font-size: 20px; }
.hero { display: flex; align-items: center; gap: 48px; padding: 72px 72px 56px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.avatar-ring { width: 120px; height: 120px; border-radius: 50%; background: linear-gradient(135deg, #7c3aed, #ec4899); padding: 3px; flex-shrink: 0; }
.avatar { width: 100%; height: 100%; border-radius: 50%; background: #1a0a2e; display: flex; align-items: center; justify-content: center; font-size: 52px; }
.status { display: flex; align-items: center; gap: 6px; font-size: 12px; color: #22c55e; margin-top: 8px; justify-content: center; }
.dot { width: 6px; height: 6px; border-radius: 50%; background: #22c55e; animation: blink 1.5s infinite; }
@keyframes blink { 0%,100%{opacity:1}50%{opacity:0.3} }
h1 { font-size: 40px; font-weight: 900; margin-bottom: 12px; } h1 span { color: #a855f7; }
.hero-text p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 16px; max-width: 540px; }
.hero-tags { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 20px; }
.hero-tags span { padding: 6px 14px; border-radius: 20px; background: rgba(168,85,247,0.1); border: 1px solid rgba(168,85,247,0.2); color: #c084fc; font-size: 13px; font-weight: 600; }
.hero-links { display: flex; gap: 10px; }
.hl-btn { padding: 10px 20px; border-radius: 10px; text-decoration: none; font-size: 14px; font-weight: 700; transition: all 0.2s; }
.github { background: rgba(255,255,255,0.08); color: white; border: 1px solid rgba(255,255,255,0.12); }
.twitter { background: rgba(29,155,240,0.1); color: #1d9bf0; border: 1px solid rgba(29,155,240,0.2); }
.mail { background: rgba(168,85,247,0.1); color: #a855f7; border: 1px solid rgba(168,85,247,0.2); }
.featured-post { padding: 48px 72px; border-bottom: 1px solid rgba(255,255,255,0.06); background: rgba(168,85,247,0.04); }
.fp-tag { color: #a855f7; font-size: 12px; font-weight: 700; letter-spacing: 2px; margin-bottom: 12px; }
.featured-post h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.featured-post p { color: #6b7280; font-size: 16px; line-height: 1.7; margin-bottom: 14px; max-width: 680px; }
.fp-meta { display: flex; gap: 10px; font-size: 13px; color: #4b5563; margin-bottom: 16px; }
.read-btn { display: inline-block; color: #a855f7; text-decoration: none; font-weight: 700; font-size: 15px; }
.posts { padding: 48px 72px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.posts h3 { font-size: 20px; font-weight: 800; margin-bottom: 20px; }
.posts-list { display: flex; flex-direction: column; }
.post-item { display: flex; justify-content: space-between; align-items: center; padding: 16px 0; border-bottom: 1px solid rgba(255,255,255,0.05); text-decoration: none; color: inherit; transition: padding-left 0.2s; } .post-item:hover { padding-left: 8px; }
.pi-left { display: flex; gap: 14px; align-items: center; }
.pi-emoji { font-size: 24px; width: 40px; }
.pi-left div strong { display: block; font-size: 15px; font-weight: 700; margin-bottom: 2px; } .pi-left div span { color: #6b7280; font-size: 12px; }
.pi-date { color: #4b5563; font-size: 13px; flex-shrink: 0; }
.newsletter-section { padding: 48px 72px; text-align: center; }
.newsletter-section h3 { font-size: 24px; font-weight: 800; margin-bottom: 8px; } .newsletter-section p { color: #6b7280; margin-bottom: 20px; }
.nl-form { display: flex; gap: 10px; max-width: 400px; margin: 0 auto; }
.nl-form input { flex: 1; height: 46px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.06); color: white; padding: 0 16px; font-size: 14px; outline: none; }
.nl-form button { height: 46px; padding: 0 20px; border-radius: 12px; border: none; background: #a855f7; color: white; font-weight: 700; cursor: pointer; }
